#!/usr/bin/env node

/**
 * GSD-QDRANT MCP Server
 * 
 * Provides MCP tools for cross-project knowledge retrieval and management.
 * This server connects to Qdrant and exposes tools for searching and retrieving
 * relevant context from the unified GSD knowledge base.
 */

const { McpServer } = require('@modelcontextprotocol/sdk/server/mcp.js');
const { StdioServerTransport } = require('@modelcontextprotocol/sdk/server/stdio.js');
const { z } = require('zod');
const { QdrantClient } = require('@qdrant/js-client-rest');
const path = require('path');
const fs = require('fs');

// Read version from this package's package.json (single source of truth)
const MCP_PKG_PATH = path.join(__dirname, 'package.json');
const SERVER_VERSION = (() => {
  try {
    return JSON.parse(fs.readFileSync(MCP_PKG_PATH, 'utf8')).version || '0.0.0';
  } catch (_) {
    return '0.0.0';
  }
})();

// Read environment variables
const QDRANT_URL = process.env.QDRANT_URL || 'http://localhost:6333';
const COLLECTION_NAME = process.env.COLLECTION_NAME || 'gsd_memory';
const VECTOR_NAME = process.env.VECTOR_NAME || 'fast-all-minilm-l6-v2';
const PROJECT_ROOT = process.cwd();

// Load the GSDKnowledgeSync module
// Strategy: try npm module resolution first (works for global/local npm installs),
// then fall back to relative paths (works for local development/symlink).
let GSDKnowledgeSync;

try {
  // 1. Try npm module resolution — works when gsd-qdrant-knowledge is installed as a dependency/peer dep
  const resolved = require.resolve('gsd-qdrant-knowledge');
  GSDKnowledgeSync = require(resolved).GSDKnowledgeSync;
} catch (npmErr) {
  try {
    // 2. Fallback: relative path from source directory
    // When running from source: src/gsd-qdrant-mcp/index.js -> ../../index.js (project root)
    const fallbackPath = path.resolve(__dirname, '..', '..');
    const indexFile = path.join(fallbackPath, 'index.js');
    if (fs.existsSync(indexFile)) {
      GSDKnowledgeSync = require(indexFile).GSDKnowledgeSync;
    } else {
      throw new Error('gsd-qdrant-knowledge not found via npm resolution or relative path');
    }
  } catch (fallbackErr) {
    console.error(
      'Failed to load GSDKnowledgeSync.\n' +
      'Install the main package: npm install -g gsd-qdrant-knowledge\n' +
      'Error:', fallbackErr.message
    );
    process.exit(1);
  }
}

/**
 * Create the MCP server instance
 */
function createMcpServer() {
  const server = new McpServer({
    name: 'gsd-qdrant-knowledge',
    version: SERVER_VERSION,
  });

  // Tool: auto_retrieve - Automatically retrieve relevant context for a task
  server.tool(
    'auto_retrieve',
    'Automatically retrieve relevant cross-project context for the given task using semantic search.',
    {
      task: z.string().describe('The task or query to find relevant context for'),
      limit: z.number().optional().default(3).describe('Maximum number of results to return'),
      maxQueries: z.number().optional().default(2).describe('Maximum number of queries to attempt'),
      includeContent: z.boolean().optional().default(false).describe('Whether to include full content in results'),
    },
    async ({ task, limit = 3, maxQueries = 2, includeContent = false }) => {
      try {
        // Initialize Knowledge Sync
        const sync = new GSDKnowledgeSync();
        await sync.init();

        // Generate query embedding and search
        const vector = await sync.embedText(task);
        
        // Search without filter first to get top matches
        const hits = await sync.client.search(COLLECTION_NAME, { 
          vector: { name: VECTOR_NAME, vector }, 
          limit: limit * 2,
          with_payload: true, 
          with_vector: false
        });

        const projectId = PROJECT_ROOT.split(/[/\\]/).pop();

        // Rank results prioritizing cross-project reuse without excluding current project results.
        const ranked = hits.map(hit => {
          const recencyScore = Math.min(1, (Date.now() - hit.payload.timestamp) / (30 * 24 * 60 * 60 * 1000));
          const importanceScore = (hit.payload.importance || 1) / 5;
          const reusableBoost = hit.payload.reusable ? 0.08 : 0;
          const crossProjectBoost = hit.payload.project_id && hit.payload.project_id !== projectId ? 0.12 : 0;
          const sameProjectBoost = hit.payload.project_id === projectId ? 0.04 : 0;
          const score = hit.score * 0.6 + (1 - recencyScore) * 0.15 + importanceScore * 0.05 + reusableBoost + crossProjectBoost + sameProjectBoost;
          return { ...hit.payload, score };
        }).sort((a, b) => b.score - a.score).slice(0, limit);

        // Format results for MCP response
        const results = ranked.map(hit => ({
          type: hit.type,
          subtype: hit.subtype,
          project_id: hit.project_id,
          source: hit.source,
          summary: hit.summary,
          content: includeContent ? hit.content : null,
          tags: hit.tags,
          language: hit.language,
          reusable: hit.reusable,
          importance: hit.importance,
          relevance_score: hit.score,
          match_type: 'semantic',
        }));

        return {
          content: [
            {
              type: 'text',
              text: JSON.stringify({
                task,
                results,
                totalResults: ranked.length,
                projectId,
              }),
            },
          ],
        };
      } catch (err) {
        console.error('auto_retrieve error:', err);
        return {
          content: [
            {
              type: 'text',
              text: JSON.stringify({
                error: err.message,
                results: [],
              }),
            },
          ],
        };
      }
    },
  );

  // Tool: list_projects - List all projects in the knowledge base
  server.tool(
    'list_projects',
    'List all unique project IDs that have been indexed in the knowledge base.',
    {},
    async () => {
      try {
        const sync = new GSDKnowledgeSync();
        await sync.init();

        // Get all documents from the collection
        const scrollResult = await sync.client.scroll(COLLECTION_NAME, {
          limit: 1000,
          with_payload: ['project_id'],
        });

        // Extract unique project IDs (scroll returns 'points', not 'hits')
        const projects = new Set();
        for (const point of scrollResult.points) {
          if (point.payload && point.payload.project_id) {
            projects.add(point.payload.project_id);
          }
        }

        return {
          content: [
            {
              type: 'text',
              text: JSON.stringify({
                projects: Array.from(projects),
                totalProjects: projects.size,
              }),
            },
          ],
        };
      } catch (err) {
        console.error('list_projects error:', err);
        return {
          content: [
            {
              type: 'text',
              text: JSON.stringify({
                error: err.message,
                projects: [],
                totalProjects: 0,
              }),
            },
          ],
        };
      }
    },
  );

  return server;
}

// Start the server
const server = createMcpServer();
const transport = new StdioServerTransport();
server.connect(transport).catch((err) => {
  console.error('Failed to connect server:', err);
  process.exit(1);
});

const { Client } = require('@modelcontextprotocol/sdk/client/index.js');
const { StdioClientTransport } = require('@modelcontextprotocol/sdk/client/stdio.js');
const { readFileSync, existsSync } = require('fs');
const { join } = require('path');

let client = null;
let connected = false;
const CONNECT_TIMEOUT = 30000;

function readMcpConfig() {
  const configPaths = [
    join(process.cwd(), '.mcp.json'),
    join(process.cwd(), '.gsd', 'mcp.json'),
  ];

  for (const configPath of configPaths) {
    try {
      if (!existsSync(configPath)) continue;
      const raw = readFileSync(configPath, 'utf-8');
      const data = JSON.parse(raw);
      const mcpServers = data.mcpServers ?? data.servers;
      if (mcpServers && typeof mcpServers === 'object') return mcpServers;
    } catch (_) {}
  }
  return null;
}

async function connectToMcpServer() {
  if (connected) return client;

  const config = readMcpConfig();
  if (!config || !config['gsd-qdrant']) {
    console.log('[Auto-Retrieve MCP] No gsd-qdrant server configured');
    return null;
  }

  const serverConfig = config['gsd-qdrant'];
  if (!serverConfig.command) {
    console.log('[Auto-Retrieve MCP] gsd-qdrant has no command configured');
    return null;
  }

  try {
    const transport = new StdioClientTransport({
      command: serverConfig.command,
      args: serverConfig.args || [],
      env: serverConfig.env ? { ...process.env, ...serverConfig.env } : undefined,
      cwd: serverConfig.cwd,
    });

    const mcpClient = new Client({ name: 'gsd-auto-retrieve', version: '1.0.0' });
    await mcpClient.connect(transport, { timeout: CONNECT_TIMEOUT });

    client = mcpClient;
    connected = true;
    console.log('[Auto-Retrieve MCP] Connected to gsd-qdrant server');
    return client;
  } catch (err) {
    console.warn('[Auto-Retrieve MCP] Failed to connect:', err.message);
    return null;
  }
}

async function callAutoRetrieve(task, options = {}) {
  if (!client) {
    await connectToMcpServer();
    if (!client) return null;
  }

  try {
    const result = await client.callTool({
      name: 'auto_retrieve',
      arguments: {
        task,
        limit: options.limit ?? 3,
        maxQueries: options.maxQueries ?? 2,
        includeContent: options.includeContent ?? false,
      },
    }, undefined, { timeout: 30000 });

    const contentItems = result.content;
    const raw = contentItems.map(c => c.type === 'text' ? c.text ?? '' : JSON.stringify(c)).join('\n');
    return JSON.parse(raw);
  } catch (err) {
    console.warn('[Auto-Retrieve MCP] Tool call failed:', err.message);
    return null;
  }
}

function formatContext(result) {
  if (!result || !result.results || result.results.length === 0) return '';

  const lines = [
    '\n\n=== CONTESTO DA MEMORIA CROSS-PROJECT ===',
    `Task: "${result.task?.substring(0, 80) || '...'}"`,
    `Trovati ${result.results.length} risultati rilevanti:\n`,
  ];

  for (const hit of result.results) {
    lines.push('');
    lines.push(`• [${hit.type || 'unknown'}] ${hit.summary || hit.source}`);
    lines.push(`  Score: ${hit.relevance_score?.toFixed(3) || 'N/A'} | Source: ${hit.source}`);
    if (hit.match_type) lines.push(`  Match type: ${hit.match_type}`);
  }

  return lines.join('\n');
}

function createAutoRetrieveHook(options = {}) {
  const {
    enabled = true,
    minScoreThreshold = 0.25,
    limit = 3,
    autoConnect = true,
  } = options;

  if (!enabled) return null;

  return async (event, ctx) => {
    const lastUserMessage = event.payload?.messages?.[event.payload.messages.length - 1];
    if (!lastUserMessage || lastUserMessage.role !== 'user') return;

    const query = typeof lastUserMessage.content === 'string'
      ? lastUserMessage.content
      : JSON.stringify(lastUserMessage.content);

    if (!query || query.trim().length === 0) return;

    try {
      if (autoConnect && !connected) await connectToMcpServer();
      const result = await callAutoRetrieve(query, { limit });

      if (result && result.results && result.results.length > 0) {
        const relevantResults = result.results.filter(r => r.relevance_score >= minScoreThreshold);
        if (relevantResults.length > 0) {
          const contextText = formatContext(result);
          ctx.payload.messages.push({
            role: 'system',
            content: [{ type: 'text', text: contextText }],
          });
          console.log(`[Auto-Retrieve MCP] Added ${relevantResults.length} context items`);
        }
      }
    } catch (err) {
      console.warn('[Auto-Retrieve MCP] Hook execution failed:', err.message);
    }
  };
}

function registerAutoRetrieve(pi, options = {}) {
  const hook = createAutoRetrieveHook(options);

  if (hook) {
    pi.on('before_provider_request', hook);
    console.log('[Auto-Retrieve MCP] Hook registered - automatic context retrieval enabled');
  } else {
    console.log('[Auto-Retrieve MCP] Hook disabled or not available');
  }

  pi.on('session_shutdown', async () => {
    if (client) {
      await client.close();
      connected = false;
    }
  });
}

module.exports = registerAutoRetrieve;
module.exports.default = registerAutoRetrieve;

